INSERT INTO sub_areas (id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, is_active)
VALUES
  ('chengdu_museum_sa_01', 'chengdu_museum', '2F · "From Nine Heavens Emerged Chengdu" — Chengdu in the Pre-Qin Period', '二楼·九天开出一成都——先秦时期的成都', '"From nine heavens emerged a Chengdu" is taken from the Tang Dynasty poet Li Bai''s poem "Song of the Emperor''s Western Journey to the Southern Capital," with the full line reading "From nine heavens emerged a Chengdu, with ten thousand households and a thousand gates forming a picture scroll."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_01.jpg', 0),
  ('chengdu_museum_sa_02', 'chengdu_museum', '2F · "Western Shu Known as Land of Abundance" — Chengdu in the Han, Wei, Jin, Southern and Northern Dynasties Period', '二楼·西蜀称天府——两汉魏晋南北朝时期的成都', 'The "Western Shu Known as Land of Abundance" gallery is located on the 2nd floor of Chengdu Museum, as the second part of the "Flowers Weigh Down Brocade City — Chengdu Historical and Cultural Exhibition (Ancient Period)."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_02.jpg', 1),
  ('chengdu_museum_sa_03', 'chengdu_museum', 'B1F · "Man and Nature" — Behring Donation Exhibition', '负一楼·人与自然——贝林捐赠展', '"Man and Nature — Behring Donation Exhibition" is located on the basement level 1 of Chengdu Museum, and is the first nature-themed exhibition since the museum''s establishment.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_03.jpg', 2),
  ('chengdu_museum_sa_04', 'chengdu_museum', '3F · "Red Towers Glow in the Evening" — Chengdu in the Ming and Qing Period', '三楼·丹楼生晚辉——明清时期的成都', '"Red towers glow in the evening" is taken from the poem of Yang Shen, a Ming Dynasty scholar from Sichuan. The gallery is located on the 3rd floor of Chengdu Museum.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_04.jpg', 3),
  ('chengdu_museum_sa_05', 'chengdu_museum', '3F · "A Bustling Famous Metropolis" — Chengdu in the Sui, Tang, Five Dynasties, Song, and Yuan Period', '三楼·喧然名都会——隋唐五代宋元时期的成都', '"A bustling famous metropolis" is taken from the Tang Dynasty poet Du Fu''s poem "Chengdu Fu," with the line "A bustling famous metropolis, with flutes and sheng pipes alternating."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_05.jpg', 4),
  ('chengdu_museum_sa_06', 'chengdu_museum', '4F · "Flowers Weigh Down Brocade City" — Chengdu Historical and Cultural Exhibition (Modern Period)', '四楼·花重锦官城——成都历史文化陈列（近世篇）', '"Flowers Weigh Down Brocade City — Chengdu Historical and Cultural Exhibition (Modern Period)" is located on the 4th floor of Chengdu Museum, focusing on Chengdu''s modern history from the mid-19th century to the mid-20th century.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_06.jpg', 5),
  ('chengdu_museum_sa_07', 'chengdu_museum', '4F · "Flowers Weigh Down Brocade City" — Chengdu Historical and Cultural Exhibition (Folk Customs Section)', '四楼·花重锦官城——成都历史文化陈列（民俗篇）', '"Flowers Weigh Down Brocade City — Chengdu Historical and Cultural Exhibition (Folk Customs Section)" is located on the 4th floor of Chengdu Museum.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_07.jpg', 6),
  ('chengdu_museum_sa_08', 'chengdu_museum', '5F · "Puppet Theater of the Great Thousand" — Chinese Puppet Exhibition', '五楼·偶戏大千——中国木偶展', '"Puppet Theater of the Great Thousand — Chinese Puppet Exhibition" is located on the 5th floor of Chengdu Museum, adjacent to the "Shadow Dance of All Phenomena — Chinese Shadow Puppetry Exhibition."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_08.jpg', 7),
  ('chengdu_museum_sa_09', 'chengdu_museum', '5F · "Shadow Dance of All Phenomena" — Chinese Shadow Puppetry Exhibition', '五楼·影舞万象——中国皮影展', '"Shadow Dance of All Phenomena — Chinese Shadow Puppetry Exhibition" is located on the 5th floor of Chengdu Museum. It is one of the museum''s most distinctive permanent exhibitions and the largest and finest shadow puppetry thematic exhibition in China.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_09.jpg', 8),
  ('chengdu_museum_sa_10', 'chengdu_museum', 'Main Entrance Hall', '正门大厅', 'The Main Entrance Hall is the entrance space and core atrium of the new Chengdu Museum building, with a soaring ceiling of tens of meters, creating a magnificent and imposing atmosphere. The hall''s design integrates modern architectural language with ancient Shu cultural elements.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_10.jpg', 9),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_01', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Adult, Subadult and Juvenile Giant Panda Villas', '成年亚成年幼年大熊猫别墅', 'Located in the central core area of the base, this villa complex is composed of multiple independent courtyards linked together. Each courtyard includes an indoor enclosure, an outdoor activity field, perches, and a pool. The villas house pandas by age—adults over 2 years, sub-adults 1-2 years, and juveniles 6 months-1 year—with each panda having its own indoor room and shared outdoor area. Through glass walls, visitors can closely observe daily behaviors such as eating bamboo, climbing trees, sleeping, and playing in water. It is one of the areas where most visitors linger longest and take the most photos. In winter (November to next March), some pandas may be moved indoors—please refer to on-site announcements.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_01.jpg', 0),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_02', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Giant Panda Museum', '大熊猫博物馆', 'Adjacent to the South Gate entrance, the Giant Panda Museum is the first indoor stop after entering the park. The two-story museum covers about 4,000 square meters and features permanent exhibitions including "Panda Origins," "Panda Evolution," "Panda Ecology," "Panda Conservation," and "World Panda Distribution." Through fossil specimens, skeletal models, taxidermy specimens, HD videos, and interactive installations, it systematically tells the 8-million-year evolutionary story of giant pandas. The museum houses a 4D cinema (looping "Panda Mission," about 15 minutes per session)—the most popular stop for families with children and educational groups.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_02.jpg', 1),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_03', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Giant Panda Sun Nursery', '大熊猫太阳产房', 'Located in the central area of the base, adjacent to the Moon Nursery, the Sun Nursery is one of the earliest cub-rearing facilities built at the base in the 1980s. The nursery is a closed, constant-temperature building divided into multiple independent cub-rearing rooms, each accommodating one mother panda and 1-2 newborn cubs. During the cub-rearing season (approximately June to November), mother pandas spend the first few months with their newborn cubs in the nursery. Through the glass observation windows, visitors can see the pink newborn cubs gradually grow their "black eye patches." In the off-season, it is transformed into a giant panda science exhibition hall, introducing knowledge about cub-rearing, breeding research, and growth cycles.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_03.jpg', 2),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_04', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Giant Panda Star Nursery', '大熊猫星星产房', 'Located at the northernmost end of the base''s new area, adjacent to the New Area Exhibition Hall and the Panda Tower, the Star Nursery is a high-end cub-rearing facility newly opened in 2024. The nursery''s exterior features a "starry sky" theme design (deep blue facade + LED starry ceiling), with internal divisions by constellation: Big Dipper Zone, Aries Zone, Scorpio Zone, etc., each corresponding to a set of cub-rearing rooms + supporting observation windows. The nursery uses a fully enclosed constant temperature and humidity system + 24-hour AI behavior monitoring + real-time live broadcast (growth videos of newborn pandas can be watched via the base''s official WeChat account during certain periods). This nursery mainly undertakes the dual tasks of "high-end cub-rearing demonstration" and "scientific breeding" at the base. **Note**: Due to cub-rearing needs, it may not be open to the public during certain periods—please refer to on-site announcements.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_04.jpg', 3),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_05', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Giant Panda Moon Nursery', '大熊猫月亮产房', 'Located in the central core area of the base, facing the Sun Nursery across a path, the Moon Nursery is a modern cub-rearing facility expanded by the base in the 2010s. The building has a half-spherical exterior (mimicking the lunar phase) and is internally divided by "lunar phases": the Full Moon Hall serves cub-rearing families, the First Quarter Hall is a science exhibition hall, and the Last Quarter Hall is a research monitoring room. During the cub-rearing season (approximately June to November), mother pandas live here with their newborn cubs. Through the floor-to-ceiling glass, visitors can clearly see the heartwarming scenes of panda mothers holding, nursing, and grooming their cubs—making it one of the base''s "Internet celebrity check-in spots." In the off-season, the Moon Hall is transformed into a 4D cinema or themed temporary exhibition area.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_05.jpg', 4),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_06', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'South Gate', '南大门', 'Located at the southernmost end of the base facing Xiongmao Avenue, the South Gate is the base''s iconic gateway. It features a bionic design—columns mimicking the panda''s "black eye patches," a golden plaque reading "Chengdu Research Base of Giant Panda Breeding" on the lintel, and panda silhouettes with bamboo reliefs. The spacious plaza in front houses a visitor center, luggage storage, wheelchair/stroller rental, and audio guide rental. The right side has group lanes and accessible lanes. After security, visitors scan their reservation QR code or use face recognition to enter—making it the base''s busiest and most photogenic gate.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_06.jpg', 5),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_07', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'West Gate', '西门', 'Located at the westernmost end of the base, adjacent to the entrance of the "Moon" Pavilion Group and the western slope of Moon Mountain, the West Gate is the base''s secondary entrance (the South Gate is the main entrance). The West Gate uses a "panda" bionic design language consistent with the South Gate, but with a smaller scale and simpler style, mainly serving visitors arriving by car or bus from the west of Chenghua District/Xindu District. Inside the gate is a small visitor center (inquiries, wheelchair rental, guide map pickup), and outside the gate is a parking lot (about 200 spaces) and a bus stop (Bus 198, 655 to "Panda Base West Gate" stop). The West Gate is open year-round and is the designated entrance for the "Moon" Pavilion Group night session ("Bright Moon" light show 19:00-21:00).', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_07.jpg', 6),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_08', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'West Zone Moon Exhibition Complex', '西区"月"字展馆群', 'Located in the base''s west district, adjacent to the West Gate and Moon Mountain, the West Zone Moon Exhibition Complex is a themed pavilion cluster newly opened in 2024–2025. Its pavilions all use moon imagery in their names, including Moonlight Splendor, Moonlight on Snow, Moon Court, Moon Encounter, Bright Moon, and Moon Dance; some are promotional names, so refer to the on-site signs. Each pavilion is compact, at roughly 300–800 square metres, but has a distinct theme: giant-panda photography, winter panda scenes, an immersive light-and-shadow show, a coffee and cultural-creative space, or an evening light display. The complex is a landmark in the base''s evolution from a traditional zoo toward a themed resort.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_08.jpg', 7),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_09', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Red Panda Enclosure Nos. 1 and 2', '小熊猫1号2号活动场', 'Located on the east and west sides of the Moon Mountain trail in the central base, Red Panda Activity Fields No.1 and No.2 are the base''s earliest publicly opened outdoor red panda activity areas. Each field has independent fences and simulates the red panda''s native high-mountain forest—dense forest, flowing water, perches, deadwood holes, and rain shelter cabins. The two fields are connected by a walking boardwalk, allowing visitors to observe natural behaviors such as napping on branches, leaping, and curling tails to shade the sun. The area is spacious with open views. **Note the distinction from the "Red Panda Moon Nursery"**: the Moon Nursery tends toward breeding (semi-enclosed), while No.1/No.2 activity fields are open outdoor activity areas.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_09.jpg', 8),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_10', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Red Panda Moon Nursery', '小熊猫月亮产房', 'Located in the Moon Mountain area of the base, the Red Panda Moon Nursery is designed for breeding red pandas (scientific name: Ailurus fulgens, also known as "lesser panda" or "red bear-cat"). The "Moon Nursery" name comes from its proximity to the Moon Nursery area and the shared moon-phase-inspired architectural design—it does not house baby giant pandas. The area is divided into multiple semi-wild activity zones by lunar phase, each simulating the red panda''s native high-mountain forest environment, equipped with perches, deadwood, flowing water, and small wooden houses. Through glass walls and wooden fences, visitors can observe behaviors such as tree-climbing, leaping, tail-curling, and feeding. This area is one of the favorite "cute check-in spots" for families with children.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_10.jpg', 9),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_11', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'New Zone Exhibition Hall', '新区展馆', 'Located at the core of the base''s new area (northern expansion zone), adjacent to the New Area Panda Villa and the entrance to the Panda Tower, the New Area Exhibition Hall is a comprehensive hall newly built in the 2020s. The hall is divided into two floors: the first floor is the giant panda-themed science exhibition hall (fossils, skeletons, habitat panoramas, breeding research results), and the second floor houses the "Panda VR Immersive Experience Hall," "Panda Theme Post Office," and "Panda Cultural & Creative Retail." The hall exit leads directly to the Panda Tower and the new area observation deck. Outside the hall is the New Area Central Plaza, which hosts panda-themed pop-ups and seasonal science activities year-round—making it a complex node for "science + cultural creativity + experience" at the base.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_11.jpg', 10),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_12', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Panda Art Museum', '熊猫美术馆', 'Located on the east side of the New Area Central Plaza in the base, adjacent to the New Area Exhibition Hall, the Panda Art Museum is a small art museum newly built in the 2020s. The museum covers about 800 square meters, divided into two floors: the first floor is the permanent exhibition hall (displaying panda-themed paintings, sculptures, and photography works by domestic and foreign artists, about 80-120 pieces), and the second floor is the temporary exhibition hall (3-4 themed exhibitions per year, having hosted "Pandas and Children''s Paintings," "Panda Image Chronicles," "International Panda Art Biennale," etc.). The museum''s design is simple and bright, with floor-to-ceiling glass walls that let natural light become the best exhibition filter. The museum houses a cultural creative shop selling limited edition art derivatives (postcards, prints, silk scarves, T-shirts, etc.).', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_12.jpg', 11),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_13', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Panda Tower', '熊猫塔', 'Located on the north side of the New Area Central Plaza of the base, the Panda Tower is a new observation/science landmark built in the 2020s. The tower is about 30 meters tall (some sources say about 50 meters, please refer to the on-site nameplate), with an exterior shaped like a giant "panda head + bamboo leaves"—the facade features black, white, and green spliced into a "panda" outline. The tower has elevators and walking stairs; the top floor is a 360° observation deck that overlooks the entire base new area (northern expansion zone) with its villas, activity fields, nurseries, and Moon Mountain. The first floor of the tower is the "Panda Tower · Themed Coffee Area," the second floor is the "Panda Photography Gallery," and the third floor is the observation deck. There is an LED light show on the tower at night (19:00-21:00). **Note**: Information about the actual height of the Panda Tower varies between 30 meters and 50 meters—please refer to the on-site nameplate.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_13.jpg', 12),
  ('https_yoloadmin_vue_cstudiomunger_workers_dev_sa_14', 'https_yoloadmin_vue_cstudiomunger_workers_dev', 'Panda Post Office', '熊猫邮局', 'Located on the north side of the first floor of the New Area Exhibition Hall at the base, the Panda Post Office is a "Panda-themed Postal Cultural Creativity Experience Point" cooperating with China Post—it is not a traditional post office. The store mainly sells panda-themed postcards, commemorative stamp albums, commemorative seals, local stationery stickers, commemorative envelopes, and other cultural creative products. Visitors can stamp the exclusive "Panda Post Office" commemorative seal on site and mail to any country in the world (additional postage required). This "themed post office" model is common in tourist attractions both in China and abroad, functioning more like a "panda-themed cultural creativity store" + "commemorative seal experience point"—for services such as registered mail, courier, or cash withdrawal, please visit the nearest post office on Xiongmao Avenue in Chenghua District outside the base (about 1.5 km).', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/https_yoloadmin_vue_cstudiomunger_workers_dev_sa_14.jpg', 13),
  ('du_fu_thatched_cottage_sa_01', 'du_fu_thatched_cottage', 'Cao Tang Screen Wall (Thatched Cottage Screen Wall)', '草堂影壁', 'The Cao Tang Screen Wall is located at the end of the Flower Path and is one of the most popular iconic landscapes in Du Fu Thatched Cottage. The screen wall, also called the Zhaobi, is an independent wall used to block sight and decorate the facade in traditional Chinese architecture. This screen wall is built of green bricks, with the two characters "Cao Tang" inlaid in the center, each character about 1.5 meters square. The most unique feature is that the two characters "Cao Tang" use the late Qing dynasty blue and white porcelain fragment inlay technique — craftsmen carefully cut and polished hundreds of late Qing dynasty blue and white porcelain fragments, then inlaid them according to the shape of calligraphy strokes, the blue and white porcelain fragments shine in the sun, which is both simple and elegant, and is an outstanding representative of late Qing folk craft. The screen wall has a red wall behind it, facing the Flower Path in front, with green bamboos and cherry blossoms in the background, forming the most poetic picture of the cottage. Every day, a large number of visitors queue up to take photos here, capturing the Chinese-style moment when the four elements of "red wall, green tiles, porcelain shadow and flower path" are integrated, which has become one of the most representative internet-famous check-in landmarks in Chengdu.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_01.jpg', 0),
  ('du_fu_thatched_cottage_sa_02', 'du_fu_thatched_cottage', 'Firewood Gate', '柴门', 'The Firewood Gate is located on the central axis after the Hall of Poetic History and before the Gongbu Shrine, serving as a landmark landscape. In ancient times, "Chai Men" referred to a simple door made of branches and thorns, often used to describe the residence of hermits or impoverished families. Du Fu wrote in his poem "Thatched Cottage" that "The four pines stand at the gate, ten thousand bamboos sparse by the steps", and in "Field House" he also wrote "The firewood gate opens toward the river unevenly", making the Firewood Gate a true reflection of the poet''s former residence. The current Firewood Gate is a low wooden gate rebuilt according to Du Fu''s poetic imagery and the style of western Sichuan folk houses, with bamboo fences and thatched cottages on both sides, and a plaque with the characters "Chai Men" on the lintel. The "low" design of the gate is intentional — visitors must lower their heads and bend over to enter, symbolizing the poet''s noble character of not pursuing power or wealth and maintaining humility. Inside the gate, bamboo shadows dance and pines and cypresses are verdant, creating a reclusive atmosphere of "building a hut in the human world without the noise of carriages and horses".', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_02.jpg', 1),
  ('du_fu_thatched_cottage_sa_03', 'du_fu_thatched_cottage', 'Hall of Great Affairs (Da Xie)', '大廨', 'Da Xie is located behind the Main Gate and in front of the Hall of Poetic History, serving as the first main hall on the central axis. "Xie" refers to an official residence. Du Fu once served as Left Reminder and Vice Minister of Works, hence the name "Da Xie" to highlight his official status. Da Xie was originally the Mahavira Hall of Caotang Temple and was rebuilt as a reception hall and Du Fu life exhibition hall after 1949. In the center of the hall stands a standing bronze statue of Du Fu, depicted in official robes with profound gaze; the side walls display biographical panels of Du Fu, detailing his life from "Study and Travel" to "Struggles in Chang''an" and finally to "Wandering in Southwest China". The door pillars of Da Xie feature a couplet written by Qing dynasty scholar Wanyan Chongshi: "Jin River Spring Wind you claim, Thatched Cottage Renri I return", cleverly incorporating the Chengdu custom of "Visiting Thatched Cottage on Renri" (the seventh day of the first lunar month).', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_03.jpg', 2),
  ('du_fu_thatched_cottage_sa_04', 'du_fu_thatched_cottage', 'Hall of Great Elegance (Da Ya Tang)', '大雅堂', 'The Hall of Great Elegance is located on the east side of the central axis of Du Fu Thatched Cottage, the largest and most artistically valuable exhibition hall in the cottage. The word "Da Ya" comes from "Da Ya" of the "Book of Songs", representing the "righteous and elegant music" of the Western Zhou royal domain, symbolizing the orthodox poetics and cultural peak. The plaque "Da Ya Tang" in front of the hall is composed of characters from the famous Tang dynasty calligrapher Yan Zhenqing, full of momentum. The Hall of Great Elegance was originally the Mahavira Hall of Caotang Temple, and was officially converted into an art exhibition hall and opened to the public in 2002. The most famous art treasure in the hall is the large-scale colored glaze inlaid lacquer mural "Poets Walking and Chanting", the largest of its kind in China to date, with Du Fu''s life journey as the clue, bringing Li Bai, Wang Wei, Meng Haoran, Gao Shi, Cen Shen and other Tang dynasty poets together in one painting, with a grand picture and brilliant colors. The hall also displays 12 sculptures of famous poets of all dynasties, including Qu Yuan, Tao Yuanming, Xie Lingyun, Li Bai, Du Fu, Bai Juyi, Su Shi, Lu You, Li Qingzhao, Xin Qiji and other peak poets in the history of Chinese literature, allowing visitors to feel the long history of Chinese poetics in every step.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_04.jpg', 3),
  ('du_fu_thatched_cottage_sa_05', 'du_fu_thatched_cottage', 'Gongbu Shrine (Ministry of Works Shrine)', '工部祠', 'The Gongbu Shrine is located behind the Firewood Gate and east of the Shaoling Thatched Cottage Stele Pavilion, the most solemn sacrificial building at the deepest part of the central axis. Du Fu once served as Vice Minister of Works (Jianxiao Gongbu Yuanwailang), commonly known as "Du Gongbu", hence the name "Gongbu Shrine". The shrine is a traditional ceremonial hall with green tiles and white walls, housing statues of Du Fu, Huang Tingjian and Lu You, commonly known as the "Hall of Three Sages". Huang Tingjian was the founder of the "Jiangxi Poetry School" of the Northern Song Dynasty, and Lu You was a patriotic poet of the Southern Song Dynasty, both of whom admired Du Fu''s poetic art. The Gongbu Shrine enshrines them on both sides of Du Fu, showing the poetic lineage of the three. The shrine is full of plaques and couplets, among which the couplet by Qing dynasty scholar Qian Baotang "Building a hut by the desolate river, you live forever; Different eras ascending the hall, these two sages" is a famous masterpiece. In front of the shrine there are incense burners and incense tables, with constant incense throughout the year, making it the core place for visitors to mourn the poet saint and express their respect.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_05.jpg', 4),
  ('du_fu_thatched_cottage_sa_06', 'du_fu_thatched_cottage', 'Flower Path', '花径', 'The Flower Path is located on the east side of the central axis of Du Fu Thatched Cottage, a small red wall path connecting the Hall of Poetic History and the Firewood Gate. The name "Flower Path" comes from Du Fu''s poem "The flower path has never been swept for guests, the pine door is now opened for you" ("Guest Arrival"), originally referring to the small path in front of Du Fu''s residence leading to the Firewood Gate. The current Flower Path has been renovated many times and has become the most popular internet-famous check-in point in the cottage: red walls lining the path, green bamboos shading, cherry blossoms and crabapples blooming alternately in four seasons; at the end, a screen wall is inlaid with the two characters "Cao Tang" with Qing dynasty blue and white porcelain fragments, with exquisite craftsmanship and strong classical charm. Walking slowly along the Flower Path, visitors can feel the poetic imagery of "The flower path has never been swept for guests" — from Tang to Qing, this small path has welcomed countless literati and dignitaries. In spring and summer, cherry blossoms are like snow and crabapples are like rosy clouds, making it one of the most popular Chinese-style photo spots in Chengdu; in autumn and winter, red leaves dot and wintersweet is fragrant, showing another kind of quiet beauty. It is recommended to visit in the morning or evening when the light is soft, to take the most artistic red wall flower shadow photos.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_06.jpg', 5),
  ('du_fu_thatched_cottage_sa_07', 'du_fu_thatched_cottage', 'Thatched Cottage Former Residence', '茅屋故居', 'The Thatched Cottage Former Residence is located west of the Shaoling Thatched Cottage Stele Pavilion, a landmark attraction rebuilt in 1997 based on Du Fu''s poetic imagery and the style of western Sichuan folk houses, covering an area of about 5 mu. The overall building uses traditional western Sichuan farmhouse craftsmanship of bamboo-woven mud walls and wooden windows with paper seams, the roof is covered with thatch, and the front of the door has vegetable fields enclosed by fences, connected to a pond and Huanhua Stream. The interior of the cottage is simply furnished: a thatched bed, a writing desk, brushes and inkstones, poetry manuscripts, and medicine jars are restored according to Tang dynasty life style, recreating Du Fu''s impoverished life of "No dry place at the head of the bed or under the eaves, the rain drops like hemp without ceasing". A stone statue of Du Fu stands in front of the cottage, leaning on a staff with a solemn expression, as if still worrying about the country and the people here. The cottage is surrounded by green bamboos, plum trees and peach trees, with different scenery in four seasons — peach blossoms in spring, green shade in summer, yellow chrysanthemums in autumn, plum blossoms in snow in winter. Visitors can feel the great mind of "How can I get a vast mansion of a million rooms to shelter all the poor scholars of the world with joy" here, which is the core place to experience the life scene of the poet saint.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_07.jpg', 6),
  ('du_fu_thatched_cottage_sa_08', 'du_fu_thatched_cottage', 'South Gate', '南门', 'The South Gate is located on the south side of the Chengdu Du Fu Thatched Cottage Museum and is one of the secondary entrances of the cottage, mainly serving visitors entering the park from the direction of Huanhua Stream Park. The South Gate tower is in an antique architectural style, with green bricks, gray tiles and upturned eaves, echoing the main gate but more elegant and restrained. In front of the gate is close to the Huanhua Stream, with the stream water gurgling; inside the gate, bamboo shadows are dancing and the green is lush. Entering through the South Gate, visitors can directly reach the garden landscape belt connecting the south area of the cottage with Huanhua Stream Park. Compared with the main gate, the South Gate has fewer visitors and a quieter environment, making it the best entrance for visitors who want to avoid the crowds and deeply experience the quiet beauty of the cottage. Entering the park from the South Gate in the morning or evening, visitors can listen to the sound of the Huanhua Stream, watch the green bamboos swaying, and feel the poetic imagery of "The water of Huanhua Stream is at the west end, the host divined that the forest pond is quiet" (Du Fu''s "Divining Residence"). After entering from the South Gate, visitors can follow the signs northward to visit the Thatched Cottage Former Residence, Shaoling Thatched Cottage Stele Pavilion, Firewood Gate, Hall of Poetic History, and finally reach Da Xie and the main gate, taking about 2 hours in total.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_08.jpg', 7),
  ('du_fu_thatched_cottage_sa_09', 'du_fu_thatched_cottage', 'Thousand Poetry Stele Corridor', '千诗碑廊', 'The Thousand Poetry Stele Corridor is located on the east side of the central axis of Du Fu Thatched Cottage, close to the south side of the Hall of Great Elegance, and is a corridor-style building about 100 meters long. The stele corridor is composed of green bricks, green tiles and carved wooden windows, and on both sides of the corridor are inlaid with bluestone steles, on which more than 1,450 of Du Fu''s surviving poems are engraved in the form of calligraphy, which is a cultural landmark of the perfect combination of Chinese classical literature and calligraphy art. The stele calligraphy collects calligraphy works of Du Fu''s poems by calligraphy masters of all dynasties such as Su Shi, Huang Tingjian and Mi Fu of the Song Dynasty, Zhao Mengfu of the Yuan Dynasty, Dong Qichang and Wen Zhengming of the Ming Dynasty, He Shaoji and Zhao Zhiqian of the Qing Dynasty, and Yu Youren, Guo Moruo, Qi Gong, Sha Menghai of modern times, with all five scripts of seal, clerical, regular, running and cursive, making it a "small museum of Chinese calligraphy art". Walking slowly along the corridor, visitors feel as if they are strolling in the long river of history: on the left are the immortal poems of the poet saint, on the right are the brush and ink style of calligraphers, and in the middle is the sculpture group of poets in the Hall of Great Elegance. Visitors are advised to stop and appreciate in the stele corridor, each stele is a piece of history, and each calligraphy work is a kind of style.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_09.jpg', 8),
  ('du_fu_thatched_cottage_sa_10', 'du_fu_thatched_cottage', 'Shaoling Thatched Cottage Stele Pavilion', '少陵草堂碑亭', 'The Shaoling Thatched Cottage Stele Pavilion is located east of the Gongbu Shrine and serves as the core landmark of the Du Fu Thatched Cottage park. "Shaoling" is the abbreviation of Du Fu''s self-styled name "Shaoling Yelao" (Old Man of Shaoling). There was a Shaoling Plateau in Chang''an in the Han Dynasty, and Du Fu''s ancestor Du Yu of the Xiangyang Du family was a Jinzhao Du, so he called himself "Old Man of Shaoling". The stele pavilion is a wooden hexagonal pavilion with a thatched roof, supported by 6 wooden pillars, with a gourd-shaped finial, surrounded by beauty-rest chairs, and the base is built of bluestone in a hexagonal shape. In the center of the pavilion stands a huge stone tablet, on which are engraved the four majestic characters "Shaoling Cao Tang", signed by Qing Yongzheng Emperor''s brother Prince Guo Aisin Gioro Yunli. According to legend, Yunli passed through Chengdu on his way to Tibet on imperial order, made a special pilgrimage to the cottage and wrote the inscription. The inscription is in regular script with strict structure and strong bones, making it a masterpiece among inscriptions of all dynasties. Surrounded by towering ancient trees and verdant bamboo, the pavilion is the core landscape that visitors must take photos with.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_10.jpg', 9),
  ('du_fu_thatched_cottage_sa_11', 'du_fu_thatched_cottage', 'Hall of Poetic History', '诗史堂', 'The Hall of Poetic History is located behind Da Xie and serves as the core main hall on the central axis. Du Fu''s poems truly record the historical transformation of the Tang Dynasty from prosperity to decline around the An Lushan Rebellion, and are honored as "Poetic History" by later generations, hence the name "Hall of Poetic History". The plaque "Shi Shi Tang" in front of the hall was inscribed by the famous philosopher and former Peking University President Feng Youlan in 1980. In the center of the hall is a bronze bust of Du Fu created by the famous sculptor Liu Kaiqu, with a lean face and solemn expression, embodying the spirit of caring for the country and the people. The walls on both sides of the hall are inlaid with calligraphy works of Du Fu''s representative works such as "Five Hundred Words on the Way from Chang''an to Fengxian County", "The Thatched Cottage Broken by Autumn Wind", "Climbing High", "Spring View", "Three Officials" and "Three Farewells", which is a must-see for visitors to understand the essence of Du Fu''s poetry. At the back wall of the hall is a 1:1 scale restoration of a Tang dynasty poet Du Fu walking and chanting statue.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_11.jpg', 10),
  ('du_fu_thatched_cottage_sa_12', 'du_fu_thatched_cottage', 'Tang Dynasty Site', '唐代遗址', 'The Tang Dynasty Site is located at the westernmost end of the central axis of Du Fu Thatched Cottage, a Tang dynasty living site area excavated archaeologically and protected in situ. Since the 1980s, archaeologists have conducted multiple excavations within the cottage area, successively unearthing Tang dynasty house foundations, wells, porcelain, bronze ware, pottery and a large number of daily necessities, among which the location of some Tang dynasty house sites is highly consistent with the location of Du Fu''s former residence recorded in literature, providing indisputable physical evidence for the "Thatched Cottage". The site area adopts a protective display method: Tang dynasty stratigraphic sections are completely preserved and protected with glass covers, so that visitors can clearly see the original appearance of Tang dynasty architectural foundations, drainage ditches, stoves, wells and other relics. Next to the site is a small exhibition hall, which systematically displays the real life scene of Du Fu in the Chengdu Thatched Cottage through excavated artifacts, archaeological photos and literature. Here, visitors can touch the historical pulse of 1,200 years ago, making it an important place for parent-child study and in-depth understanding of Tang dynasty culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_12.jpg', 11),
  ('du_fu_thatched_cottage_sa_13', 'du_fu_thatched_cottage', 'Main Gate', '正门', 'The Main Gate is the main entrance of the Chengdu Du Fu Thatched Cottage Museum, located at the southern end of Qinghua Road and serves as the first stop for visitors. The gate tower is built in a five-pillar, three-bay Tang-style architecture with upturned eaves and grand momentum. The four golden characters "Du Fu Cao Tang" inscribed on the lintel were written by the famous writer and poet Guo Moruo in 1958, with powerful and vigorous brushstrokes, making it the most recognizable landmark of the cottage. A couplet on both sides reads: "Wanli Bridge West Residence, Baihua Pool North Villa", indicating the geographical location of the cottage. Entering the main gate, visitors can tour the Hall of Great Affairs, Hall of Poetic History, Firewood Gate, Gongbu Shrine, Shaoling Thatched Cottage Stele Pavilion, Thatched Cottage Former Residence and other attractions in turn.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/du_fu_thatched_cottage_sa_13.jpg', 12),
  ('qingyangg_sa_01', 'qingyangg', 'Main Gate (Front Gate)', '正门', 'The Main Gate is the formal entrance of the Chengdu Qingyang Palace, located on the south side of the west section of the First Ring Road, facing the city''s main road, and is magnificent. The main gate is a three-bay imitation of the official Ming and Qing style archway building, the main body is built of green bricks, covered with gray tiles and flying eaves, and the lintel has the three gilded characters "Qingyang Palace" hanging high, vigorous and simple. On both sides of the gate stands a stone carved green sheep - this is the origin of the name of Qingyang Palace: according to legend, when Laozi rode the green ox through Hangu Pass, he said "Find me in Chengdu Qingyang Market a thousand days later", and the Tang Dynasty built the temple here based on this legend. In front of the gate, the square is filled with curling incense and a crowd of visitors, and pilgrims often stop here to burn incense and pay their respects. Stepping into the main gate, you enter the outer altar area of Qingyang Palace, and you can successively pass through the Mountain Gate, Lingzu Hall, Hunyuan Hall, Bagua Pavilion, Sanqing Hall, Doumu Hall, Jade Emperor Hall and other main halls, with the central axis being symmetrical and progressive layer by layer, creating a solemn and sacred ceremonial sense of the traditional Chinese Taoist temple. The main gate is open all day, and buying a ticket to enter the park is the standard starting point for visiting Qingyang Palace.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_01.jpg', 0),
  ('qingyangg_sa_02', 'qingyangg', 'Mountain Gate (Temple Gate)', '山门', 'The Mountain Gate is the first hall-style gate after the main gate in Qingyang Palace, located between the main gate and the Lingzu Hall, and is the first gate for visitors to enter the core sacrificial area of Qingyang Palace. The Mountain Gate is a single-eave Xieshan-style building, with gray tube tile roof and vermilion red door panels, and the ridge is decorated with Taoist-style chiwen ridge beasts. The four gilded characters "Purple Air Comes from the East" are hung high on the lintel - the allusion comes from the "Liexian Zhuan" (Biographies of Immortals) in which Laozi rode the green ox westward through Hangu Pass, and Guan Ling Yinxi saw the purple air coming from the east, which is in line with the core legend of Qingyang Palace''s "Laozi''s Transformation into a Barbarian". On both sides of the gate stands a majestic stone lion, male on the left and female on the right, symbolizing the guardianship and majesty of the Taoist temple. In front of the gate, you can often see traces of men and women burning incense and paper on the floor tiles, and the air is filled with the sandalwood and the unique ancient atmosphere of the temple. The mountain gate has the ceremonial significance of "separating the secular from the sacred" in the architectural pattern of the Taoist temple. Crossing the mountain gate, you will officially enter the altar area of Qingyang Palace, and visitors should keep quiet and respect religious etiquette here. The mountain gate itself does not have a separate hall, but on both sides there are often drum towers and bell towers standing symmetrically, making it an important ceremonial space node in Qingyang Palace.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_02.jpg', 1),
  ('qingyangg_sa_03', 'qingyangg', 'Lingzu Hall (Patriarch Hall)', '灵祖殿', 'The Lingzu Hall is located after the Mountain Gate and before the Hunyuan Hall, and is the first main hall on the central axis of Qingyang Palace, as well as the first large hall that visitors see after entering the core sacrificial area of Qingyang Palace. The Lingzu Hall is a single-eave Xieshan-style brick and wood structure, with gray tiles, red walls, flying eaves, five bays wide, and a solemn atmosphere. The main worship in the hall is the Taoist "Sanqing" one of the "Lingbao Tianzun" (Heavenly Worthy of Spiritual Treasure), also known as "Shangqing Lingbao Tianzun", one of the highest deities in Taoism. The two sides of the Lingzu Hall are often accompanied by Taoist Dharma protector generals, with various shapes and exquisite painted statues. In front of the hall, there is a large incense burner, where pilgrims and visitors burn incense to worship and pray for blessings. The Lingzu Hall plays a transitional role in the overall architectural pattern of Qingyang Palace - it not only continues the "separation of secular and sacred" of the mountain gate, but also paves the way for the rituals of the Hunyuan Hall, Sanqing Hall and other main halls behind. The plaques and couplets inside and outside the hall are mostly written by famous Qing dynasty calligraphers, containing rich Taoist cultural connotations. The Lingzu Hall has been bustling with incense all year round, and is an important place to experience the Taoist atmosphere of Qingyang Palace and understand Taoist etiquette.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_03.jpg', 2),
  ('qingyangg_sa_04', 'qingyangg', 'Hunyuan Hall (Primordial Chaos Hall)', '混元殿', 'The Hunyuan Hall is located after the Lingzu Hall and before the Bagua Pavilion, and is the second main hall on the central axis of Qingyang Palace. The Hunyuan Hall was first built in the Ming Dynasty and rebuilt during the Kangxi period of the Qing Dynasty. It is one of the oldest and most historically valuable halls in Qingyang Palace. The word "Hunyuan" comes from the Taoist classic "Dao De Jing" (Tao Te Ching) "The Tao gives birth to one, one gives birth to two, two gives birth to three, three gives birth to all things" cosmology, symbolizing the original state of heaven and earth not yet divided and chaos at the beginning. The main deity in the hall is the "Dao De Tianzun" (Heavenly Worthy of the Way and its Virtue), one of the "Sanqing" in Taoism, i.e. Laozi Li Er, the philosopher of the Spring and Autumn Period. In the center of the hall, a bronze statue of Laozi is enshrined, holding a ruyi in his left hand and pressing his knee with his right hand, looking peaceful. The statue of Laozi is one of the treasures of Qingyang Palace, and it is said that on the 15th day of the second lunar month, the birthday of Laozi, a grand birthday ceremony will be held in the palace. The Hunyuan Hall is a single-eave Xieshan-style building, with exquisite Taoist ridge beasts on the roof, and the wood carvings, brick carvings and stone carvings inside and outside the hall are exquisite, integrating the architectural aesthetics of the Ming and Qing dynasties. In front of the Hunyuan Hall, Taoists often chant sutras and confess here, which is an important place to experience the core connotation of the Taoist culture of Qingyang Palace.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_04.jpg', 3),
  ('qingyangg_sa_05', 'qingyangg', 'Bagua Pavilion (Eight Trigrams Pavilion)', '八卦亭', 'The Bagua Pavilion is located after the Hunyuan Hall and before the Sanqing Hall, and is one of the most iconic buildings in Qingyang Palace, as well as a perfect combination of the architectural art and Taoist philosophy of Qingyang Palace. The Bagua Pavilion is a double-eave octagonal pyramidal building, and the body of the pavilion is mainly decorated with green glazed tiles - the eight sides of the pavilion roof and the eight sides of the pavilion body correspond to the eight trigrams of Qian, Kun, Zhen, Xun, Kan, Li, Gen and Dui. The center of the pavilion roof is a black and white Taiji diagram, with the Yin and Yang fish of the Taiji embracing and rotating, symbolizing the cosmic evolution of "The Tao gives birth to one, one gives birth to two, two gives birth to three, three gives birth to all things". The whole Bagua Pavilion has a unique shape and elegant color, the green glazed tiles shine in the sun, forming a sharp contrast with the surrounding red walls and gray tiles, and is a masterpiece of traditional Chinese Taoist temple architectural art. The pavilion originally enshrined a bronze statue of Laozi riding a green ox through Hangu Pass (which was moved to another place during some periods), which is the core cultural symbol of Qingyang Palace. The Bagua Pavilion is not only the visual "commanding height" of Qingyang Palace, but also carries the Taoist cosmology of "the unity of heaven and man" - visitors standing under the pavilion and looking up at the Taiji diagram can intuitively feel the core idea of "Tao follows nature" in Taoism. The square in front of the pavilion often hosts Taoist cultural exhibitions and Tai Chi performances, making it a must-visit place to experience the Taoist culture of Qingyang Palace.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_05.jpg', 4),
  ('qingyangg_sa_06', 'qingyangg', 'Sanqing Hall (Three Pure Ones Hall)', '三清殿', 'The Sanqing Hall is located after the Bagua Pavilion and before the Doumu Hall, and is the largest and most prestigious hall in Qingyang Palace, as well as the core main hall of the entire Qingyang Palace building complex. The Sanqing Hall is a large double-eave Xieshan-style brick and wood structure, with gray tiles, red walls, carved beams and painted rafters, magnificent and solemn. The main deities in the hall are the highest Taoist gods "Sanqing": Yuqing Yuanshi Tianzun (Heavenly Worthy of the Primordial Beginning), Shangqing Lingbao Tianzun (Heavenly Worthy of Spiritual Treasure), and Taiqing Dao De Tianzun (Heavenly Worthy of the Way and its Virtue, i.e. Laozi). The three pure ones sit side by side on a lotus platform, each Tianzun statue is several meters tall, with a peaceful expression and deep eyes. The plaque "Sanqing Hall" in the hall is written by a famous calligrapher in the Qing Dynasty, vigorous and powerful. The stone steps, moon platforms and railings in front of the Sanqing Hall are all carved from white marble, echoing the Taoist statues and painted murals in the hall, forming the most solemn and sacred sacrificial space in Qingyang Palace. Every year during major Taoist festivals such as the Spring Festival and the birthday of the Sanqing, a grand Zhaijiao ceremony will be held in front of the Sanqing Hall, which is the most concentrated place for Taoist cultural activities in Qingyang Palace. The Ming and Qing wood carvings, stone carvings and paintings inside and outside the hall are of high artistic value, and are precious objects for studying the history of Chinese Taoist architecture and art. The Sanqing Hall is the core place for visitors to understand Qingyang Palace and the highest deity system of Taoism. Visitors are advised to keep quiet and respect religious etiquette when visiting.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_06.jpg', 5),
  ('qingyangg_sa_07', 'qingyangg', 'Doumu Hall (Mother of the Big Dipper Hall)', '斗姥殿', 'The Doumu Hall is located after the Sanqing Hall and before the Jade Emperor Hall, and is one of the core halls on the central axis of Qingyang Palace. The Doumu Hall is a single-eave Xieshan-style brick and wood structure, with gray tiles, red walls, and a solemn atmosphere. The main deity in the hall is Doumu Yuanjun, also known as "Doumou Yuanjun", the highest goddess in the Taoist star worship system, who is in charge of the constellations in the sky, fertility and longevity in the mortal world. The image of Doumu Yuanjun is unique, with three faces and four heads, or three faces and eight heads, holding the sun and moon in her hands or holding the sun and moon beads, symbolizing her supreme divine power over the stars of the heavens. On both sides of the Doumu Hall are often accompanied by the "Big Dipper Seven Star Lords" - the statues of the seven star lords Tianshu, Tianxuan, Tianji, Tianquan, Yuheng, Kaiyang and Yaoguang. The Doumu Hall has a very high status in folk beliefs, and it is said that Doumu Yuanjun is one of the incarnations of the "Goddess of Child Giving", and pilgrims often pray here for offspring, health and longevity. Every year on the ninth day of the ninth lunar month, the birthday of Doumu, a grand blessing ceremony will be held in front of the hall. The Taoist statues and painted murals in the Doumu Hall are exquisite, and the stone and wood carvings outside the hall are exquisite. The Doumu Hall is a representative place to experience the Taoist star worship and female deity belief in Qingyang Palace, and is also a popular hall for visitors to pray and make wishes.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_07.jpg', 6),
  ('qingyangg_sa_08', 'qingyangg', 'Jade Emperor Hall (Fu-Lu-Shou Screen Wall)', '玉皇殿（福禄寿照壁）', 'The Jade Emperor Hall is located after the Doumu Hall and before the Descent Birth Platform and Preaching Platform, and is the last main hall on the central axis of Qingyang Palace. The Jade Emperor Hall is a double-eave Xieshan-style brick and wood structure, with gray tiles, red walls and a grand scale. The main deity in the hall is the Jade Emperor - one of the highest deities in the Taoist pantheon, second only to "Sanqing", who is in charge of the three realms and ten directions, the master of all gods, so it is also called "Tiangong" (Lord of Heaven). In front of the Jade Emperor Hall is an exquisite screen wall called the "Fulu Shou Screen Wall", which is the most popular blessing check-in landscape in Qingyang Palace. The screen wall is built of green bricks, with the three characters "Fulu Shou" inlaid in the center. "Fu" represents good fortune and well-being, "Lu" represents fame and salary, and "Shou" represents longevity and well-being - the three characters together represent the three most simple and beautiful wishes of the Chinese people. The three characters "Fulu Shou" use the same late Qing dynasty blue and white porcelain fragment inlay technique as the "Caotang" Screen Wall of Du Fu Thatched Cottage. Craftsmen cut and polished hundreds of blue and white porcelain fragments and then inlaid them together. The blue and white porcelain fragments shine in the sun, which is an outstanding representative of late Qing folk craft. Many visitors queue up here to take photos and touch the word "Fu" to pray for good luck. The Jade Emperor Hall is the "finale" of the Qingyang Palace building complex, and a grand birthday ceremony will be held every year on the ninth day of the first lunar month, the birthday of the Jade Emperor.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_08.jpg', 7),
  ('qingyangg_sa_09', 'qingyangg', 'Descent Birth Platform and Preaching Platform', '降生台与说法台', 'The Descent Birth Platform and Preaching Platform are located after the Jade Emperor Hall and before the Purple Gold Platform, and are two commemorative buildings with profound cultural connotations in Qingyang Palace. The Descent Birth Platform is a commemorative building in Qingyang Palace for the birth of Laozi. According to legend, Laozi Li Er was born in Ku County, Chu State (now Luyi, Henan). In order to commemorate this "Taoist Master" and promote Taoist culture, the Taoists of later generations specially built this platform in Qingyang Palace. The Descent Birth Platform is a high platform built of green bricks, on which there were originally sculptures or murals on the theme of the birth legend of Laozi, some of which were lost due to age, but the platform base and pattern are still clearly visible, and it is an important part of the "Laozi''s Transformation into a Barbarian" cultural narrative of Qingyang Palace. The Preaching Platform is adjacent to the Descent Birth Platform, built to commemorate Laozi''s westward journey through Hangu Pass and his writing of the 5,000-character Tao Te Ching at the request of Guan Ling Yinxi. The platform originally had a statue of Laozi riding a green ox out of the pass with "purple air coming from the east" or related stone carvings, symbolizing the spread and dissemination of Taoist thought. The two platforms stand side by side in the east and west, complementing each other, and together tell the complete narrative of Laozi from birth, cultivation to the creation of Taoist philosophy, which is the core memorial space of the Taoist history and culture of Qingyang Palace. Visitors can stop here and deeply feel the philosophical mood of "Tao follows nature" and "do nothing and everything is done", which is a must-visit place to experience the deep connotation of the Taoist culture of Qingyang Palace.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_09.jpg', 8),
  ('qingyangg_sa_10', 'qingyangg', 'Purple-Gold Terrace (Tang King Hall)', '紫金台（唐王殿）', 'The Purple Gold Platform, also known as the Tang King Hall, is located after the Descent Birth Platform and Preaching Platform, and is one of the most historically legendary commemorative buildings at the westernmost end of Qingyang Palace. The origin of the Purple Gold Platform is closely related to Emperor Xuanzong of Tang Li Longji: it is said that during the Anshi Rebellion (after 755 AD), Tang Xuanzong took refuge in Shu, once stayed in Qingyang Palace, and dreamed of Laozi appearing at night in the palace, telling him an omen of peace in the world. Tang Xuanzong, in gratitude for Laozi''s kindness, ordered the rebuilding of Qingyang Palace and built the Purple Gold Platform here in commemoration. The Purple Gold Platform is a high-platform building built of green bricks, on which there were originally portraits or statues of Tang Xuanzong, some of which were lost due to age, but the platform base, steps and pattern are still clearly visible. In front of the platform, there are often stone inscription steles recording the legend of Tang Xuanzong''s visit to Shu and the historical evolution of Qingyang Palace. The Purple Gold Platform has a "finale" status in the architectural pattern of Qingyang Palace - it is not only the end of the Taoist cultural narrative of Qingyang Palace (the spread of Laozi''s thought), but also the node of the historical narrative of Qingyang Palace (Tang Xuanzong''s visit to Shu), connecting the Taoist legend and historical truth. The Purple Gold Platform is often visited by tourists, and is a representative place in Qingyang Palace to understand the history of the Tang Dynasty and the interaction between emperors and Taoism. The whole Purple Gold Platform is not large in scale but has profound cultural connotations, and is the "finale" scenic spot on the tour route of Qingyang Palace.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_10.jpg', 9),
  ('qingyangg_sa_11', 'qingyangg', 'Tea Garden and Laozhuang Academy (Lao-Zhuang Academy)', '茶园与老庄书院', 'The Tea Garden and Laozhuang Academy are located in the middle and rear of the Qingyang Palace building complex, near the back gate of Qingyang Palace, and are the most leisurely characteristic cultural space in Qingyang Palace. The Tea Garden is a typical Sichuan-Western folk-style teahouse building, with green bricks, gray tiles, rattan chairs, bamboo tables, and green plants. The tea garden provides authentic Chengdu gaiwan tea (Bitan Piaoxue, Zhuyeqing, etc.), Sichuan-Western snacks (San Da Pao, Zhong Dumplings, Lai Tangyuan, Fuqi Feipian, etc.), Sichuan-style cold dishes and health tea. Visitors can rest in the tea garden after visiting the halls, brew a pot of tea, taste some snacks, listen to a section of Sichuan opera Qingyin, watch a tea art performance, and experience the most authentic "teahouse culture" in Chengdu. The Laozhuang Academy is adjacent to the tea garden and is a special academic space for displaying, researching and disseminating Taoist culture in Qingyang Palace. The academy is named after the two representative figures of Taoism - Laozi (Li Er) and Zhuangzi (Zhuang Zhou). The academy has a collection of Taoist classic versions such as the "Tao Te Ching" and "Zhuangzi", Taoist calligraphy stone inscriptions and rubbings from past dynasties, and books on Taoist culture research. The cloister outside the academy often has calligraphy exhibitions, displaying calligraphy works of famous Taoist articles. The Tea Garden and the Laozhuang Academy together form a "dynamic-static" combination of leisure and cultural system in Qingyang Palace - the halls are "dynamic" religious and cultural spaces, and the tea garden and academy are "static" cultural leisure spaces, allowing visitors to find a quiet place in the hustle and bustle of the city after pilgrimage and worship, and experience the "Taoist slow life".', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/qingyangg_sa_11.jpg', 10),
  ('sichuan_museum_sa_01', 'sichuan_museum', 'Main Entrance & Lobby (Chengdu Museum)', '正门与大厅（成都博物院）', 'The main entrance and lobby deliver the Chengdu Museum''s first impression. Designed by master architect Xu Shanggui under the "gold-inlaid-jade" concept, the facade merges Han-dynasty pictorial-brick motifs with a modern glass curtain wall. Two Han-style stone beasts (Shiyi & Bixie) flank the entry. The atrium''s central relief, "Hua Chong Jin Guan Cheng – A Historical Journey through Chengdu," unfolds Chengdu''s urban evolution from Sanxingdui–Jinsha through Qin-Han, Tang-Song, and Ming-Qing. Dougong brackets, caisson ceilings, and Shu-brocade patterns abstract the western-Sichuan sloped roofline—turning the architecture itself into the museum''s first exhibit. Here visitors collect audio guides, store luggage, and scan in to begin their tour.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_01.jpg', 0),
  ('sichuan_museum_sa_02', 'sichuan_museum', 'Sichuan Han Dynasty Ceramic & Stone Art Gallery (Chengdu Museum, 1F)', '四川汉代陶石艺术馆（成都博物院一楼）', 'Located on the museum''s 1F core, this is China''s only gallery dedicated to Sichuan Han-dynasty pictorial bricks and carved stones. Hundreds of masterpieces from Pengshan, Xinjin, Pixian, and Xindu are organized into four zones: manor-farming and archery-harvest, markets and salt-wells, mythic auspiciousness, and chariots-banquets. The iconic "Archery and Harvest" brick captures a hunter, startled wild geese, and rippling rice fields; the "Salt Well" brick documents the deep-well brine extraction at Linqiong (home of Zhuo Wenjun), the world''s earliest visual record of salt production. Smiling storytellers, drummers, and qin-players in the pottery zone are evidence of Han-era Sichuan''s cheerful, secular folk spirit. Multimedia stations let visitors zoom into brick details and hear expert commentary.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_02.jpg', 1),
  ('sichuan_museum_sa_03', 'sichuan_museum', 'Ancient Sichuan – Prehistoric Era Hall (Chengdu Museum, 2F)', '远古四川·史前时期展厅（成都博物院二楼）', 'This hall is the prologue of the "Hua Chong Jin Guan Cheng" chronological exhibition. The trail begins with the 2.04-million-year-old Wushan Man tooth fossil, moves through Ziyang Man (Palaeolithic), Gaoshan Ancient City, the Baodun culture, and culminates in the Sanxingdui–Jinsha sites—revealing how the Chengdu Plain nurtured China''s earliest, largest, and most imaginative ancient Shu civilization. Highlights include a section model of Baodun''s city wall (~2700 BCE), 4,500-year-old paddy-field remains, and replicas of face-painted pottery pots, bird-head ladle handles, and jade yazhang ritual blades. Immersive projections let visitors "enter" ancient Shu sacrificial grounds, understanding Sanxingdui–Jinsha not as alien imports but as the indigenous pinnacle of Sichuan''s own civilizational arc.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_03.jpg', 2),
  ('sichuan_museum_sa_04', 'sichuan_museum', 'Ancient Sichuan – Pre-Qin to Qin-Han-Three Kingdoms Hall (Chengdu Museum, 2F)', '古代四川·先秦至秦汉三国展厅（成都博物院二楼）', 'This hall is Chapter 2 of the "Hua Chong Jin Guan Cheng" chronological exhibition. The narrative moves from the legendary Twelve Shu Kings (Cancong, Du Yu, Kaiming) to the Qin conquest of Ba and Shu (316 BCE), the "colonization of Shu" policies, Li Bing''s construction of Dujiangyan (256 BCE), Wen Weng''s schools, and Han-era artifacts—the Li Bing stone statue, storyteller figurines, and cliff-tomb models. A Dujiangyan sand-table with dynamic water projection reveals the engineering genius of Yuzui, Feishayan, and Baopingkou. The finale explores Three Kingdoms Shu—Shu brocade, Zhuge crossbow, and the zhi-bai coin—showing how the "Land of Abundance" moved from periphery to center stage in the Han–Three Kingdoms era. Allow at least 40 minutes for the dense exhibits.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_04.jpg', 3),
  ('sichuan_museum_sa_05', 'sichuan_museum', 'Ba-Shu Bronze Ware Gallery (Chengdu Museum, 2F)', '巴蜀青铜器馆（成都博物院二楼）', 'This is one of the most academically rich galleries in the museum. The collection focuses on late Warring States to early Western Han Ba-Shu bronzes, organized into ritual, weapon, musical, daily-use, and coin categories. The headline piece—the "Inlaid Bronze Pot with Banquet, Music, Water and Land Battle Scenes"—stands ~40 cm tall and uses metal inlay to depict five scenes (mulberry-picking, archery, feasting, water battle, land battle) with nearly 200 miniature figures, hailed as "the earliest bronze War and Peace." Tiger-pattern ge-daggers, willow-leaf swords, and boat-coffin bronze plaques reflect Ba-Shu''s tiger worship and fishing-hunting culture. Multimedia stations let visitors rotate 3D models, zoom inlay details, and compare the lineage differences between Ba-Shu and Central Plains bronzes.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_05.jpg', 4),
  ('sichuan_museum_sa_06', 'sichuan_museum', 'Ceramics Gallery (Chengdu Museum, 2F)', '陶瓷馆（成都博物院二楼）', 'Located on 2F East Wing, the gallery chronologically presents ~400 representative pieces: Han green-glazed pottery, Tang Qingyao tri-colors, Song-Yuan Jingdezhen bluish-white porcelain, Ming-Qing blue-and-white and wucai, and late-Qing/Republic qianjiang enamels. The Qionglai (Qingyao) kiln takes center stage—China''s largest southwestern folk kiln system, whose oil-saving lamps, stamped stem-cups, and flambé-glaze bowls were praised by Lu You''s "Laoxue''an Notes." A multimedia reconstruction of the Shifangtang kiln site lets visitors follow clay-purifying, throwing, glazing, firing, and unloading steps. The finale showcases "export porcelain" from Chengdu customs and the Ya''an Tea-Horse Road, revealing Chengdu''s role as a tea-horse corridor and Southern Silk Road hub in East-West ceramic trade.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_06.jpg', 5),
  ('sichuan_museum_sa_07', 'sichuan_museum', 'Zhang Daqian Painting & Calligraphy Gallery – Dafengtang (Chengdu Museum, 2F)', '张大千书画馆·大风堂（成都博物院二楼）', 'Zhang Daqian (1899–1983) is one of the 20th century''s most internationally influential Chinese painters. The museum—located in his long-time creative base of Chengdu—hosts the Dafengtang memorial hall, displaying his artistic evolution in three phases. Early works like "Lotus" and "Imitation of Shitao Landscape" reveal literati elegance; the mid-period features 1:1 copies of Dunhuang Mogao frescoes and previously unpublished sketch drafts from his 1941–43 pilgrimage; the late-period showcases splash-ink and splash-color masterpieces such as "Ten-Thousand Li of the Yangtze," "Peach Blossom Spring," and "Love-Traces Lake." The gallery''s vitrine also displays Daqian''s personal brushes, seals, palette, and Panama hat—primary sources for biographical research.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_07.jpg', 6),
  ('sichuan_museum_sa_08', 'sichuan_museum', 'Painting & Calligraphy Gallery (Chengdu Museum, 2F)', '书画馆（成都博物院二楼）', 'Echoing the Zhang Daqian hall, this gallery is organized into four themes: Song academic style, Yuan literati, Ming-Qing Ba-Shu masters, and modern Shu-connected artists. Highlights include rubbing-and-original editions of Su Shi''s "Gongfu Tie," Wen Tong''s "Huzhou Bamboo School" ink-bamboos, Yang Shen''s running-script, works by Tang Yin, Wen Zhengming, Dong Qichang, plus modern masters with Shu ties—Kang Youwei, Liang Qichao, Yu You-ren, Guo Moruo, Xu Beihong, Qi Baishi, and Huang Binhong. Museum-grade temperature-controlled vitrines rotate exhibits seasonally: Spring Festival couplets, Duanwu fan paintings, and an autumn Ba-Shu master show. Digital kiosks allow searching the museum''s full calligraphy and painting archive by dynasty, author, or theme.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_08.jpg', 7),
  ('sichuan_museum_sa_09', 'sichuan_museum', 'Tibetan Buddhist Artifacts Gallery (Chengdu Museum, 3F)', '藏传佛教文物馆（成都博物院三楼）', 'Located on 3F West Wing, this hall reflects Sichuan''s role as a Sino-Tibetan cultural hub. The collection centers on Ming-Qing gilt-bronze statues, thangkas, mandalas, ritual implements, dharma bells, gyaling horns, and Tibetan sutra woodblocks, organized by five major schools: Tsongkhapa lineage, Gelug, Nyingma, Sakya, and Kagyu. The highlight is an ~80 cm Yongle-era (Ming) imperial gilt-bronze Buddha of extraordinary craftsmanship; alongside a set of 13 ~1.5m × 1m thangkas depicting the Life of Shakyamuni, still vibrant after five centuries. An interactive "mani wheel" wall lets visitors spin carved wooden prayer wheels and experience daily Tibetan Buddhist practice. The hall is the best window into western Sichuan Tibetan-region culture and history.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_09.jpg', 8),
  ('sichuan_museum_sa_10', 'sichuan_museum', 'Wanfo Temple Stone Sculpture Gallery (Chengdu Museum, 3F)', '万佛寺石刻馆（成都博物院三楼）', 'Wanfo Temple, near Tongjin Bridge outside Chengdu''s west gate, was one of the city''s most important official temples from the Southern Dynasties through the Tang. Excavated in four campaigns between 1882 and 1953, the site yielded hundreds of sculpture fragments—the most important Southern Dynasties Buddhist stone-carving discovery in southern China after Yungang and Longmen. The gallery is organized into five periods: Liang, Northern Zhou, Sui, Early Tang, and High Tang. Highlights include a 523 CE Liang Pingtong-4 statue, Ashoka-style pagodas, a Sui Daye Amitabha, an Early Tang yab-yum Buddha, and a High Tang guardian figure. Wanfo carvings uniquely merge the "Cao Yi Chu Shui" (Cao-style flowing-drapery) and "Wu Dai Dang Feng" (Wu-style fluttering-ribbon) styles—key evidence for the "Southern Dynasties sinicization" of Chinese Buddhist sculpture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_10.jpg', 9),
  ('sichuan_museum_sa_11', 'sichuan_museum', 'Sichuan Ethnic Cultural Relics Gallery (Chengdu Museum, 3F)', '四川民族文物馆（成都博物院三楼）', 'This gallery is the museum''s premier window into the "diverse yet unified" Chinese nation on Sichuan soil. Sections cover Tibetan (Jiarong, Amdo, Khampa), Qiang, Yi (Liangshan), Miao, Tujia, Naxi, Lisu, Mongol, Hui, and Manchu groups. Costumes are the highlights: Jiarong Tibetan women''s colorful robes with turquoise-coral-amber headdresses, Liangshan Yi men''s "chaerwa" woolen cloaks and "tianbaba" hero-knot, Qiang cross-stitch embroidery and silver plaques, Miao pleated skirts and batik, and Tujia "Xilankapu" brocade. The gallery also displays ethnic musical instruments (Qiang flute, mouth harp, long-necked qin, mabu), ritual objects (Bon-buddhist butter flowers, Bimo divining cylinders, Dongba scriptures), tools, and wedding items. The closing "ethnic unity" relief wall embodies the vision of a Chinese national community.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_11.jpg', 10),
  ('sichuan_museum_sa_12', 'sichuan_museum', 'Arts & Crafts Gallery (Chengdu Museum, 3F)', '工艺美术馆（成都博物院三楼）', 'Located at the end of 3F East Wing, the gallery brings together over ten Ba-Shu craft genres: Shu brocade, Shu embroidery, Chengdu lacquerware, silver filigree, bamboo weaving, porcelain-bamboo composite, ivory and jade carving, gold-silver inlay, paper-cut, shadow puppetry, and masks. The center stage replicates a late-Qing Shu-brocade "great-flower-loom" wooden machine—heritage inheritors demonstrate "picking-and-tying pattern cards" at scheduled times, letting visitors watch "wanzi" and "bing-mei" patterns take form. The double-sided Shu-embroidered panda won the Hundred Flowers Gold Award; the silver-filigree showcase displays "flat-fill" filigree of intricate complexity; the porcelain-bamboo pieces wrap hairlike bamboo strips around thin porcelain. The closing "Intangible Heritage Experience Zone" offers Shu-embroidered fans, silver filigree, and paper-cut classes—reserve at the service desk.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_12.jpg', 11),
  ('sichuan_museum_sa_13', 'sichuan_museum', 'Exit & Surroundings (Chengdu Museum)', '出口与周边（成都博物院）', 'The museum''s exit integrates with the "Qinghua Road Museum Cluster" master plan. From the south gate, walking ~800m south leads to Dufu Thatched Cottage (5A scenic area); the opposite side of the road opens onto Huanhuaxi Park and the "Poetry Avenue" stone corridor; 1.5 km east reaches Sichuan University''s West China campus (bell tower, Maode Hall, old library); another 2 km east brings you to Sichuan Provincial Library, Sichuan Science & Technology Museum, and Tianfu Square—Chengdu''s dense cultural core. The exit plaza hosts a cultural-creative shop and "Chengdu Gifts" souvenir store, with replica artifacts, Shu-brocade ties, panda plush, and Sichuan-opera mask toys. Adjacent F&B includes Starbucks, %Arabica, and Bread Talk. In late autumn, photograph the golden ginkgo leaves along Qinghua Road—a perfect Chengdu-style farewell contrasting the museum''s solemnity.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/sichuan_museum_sa_13.jpg', 12),
  ('wenshuyuan_sa_01', 'wenshuyuan', 'Sutra Repository (Chen Scripture Hall)', '藏经楼（宸经楼）', 'The Canon Library, also called "Chenjing Lou," is the fifth hall on the central axis—originally built by Chan Master Cidu and rebuilt by Abbot Benyuan in 1824. Standing 15.84 m tall in two stories, it is the monastery''s central repository for sutras and treasures. The name "Chenjing" comes from Kangxi''s imperial calligraphy. Beyond the Ming and Qing Buddhist canons (Long, Pingqia, Taisho, Qianlong Da Zangjing and continuations), the library preserves Kangxi''s "Konglin" hand and his Mi Fu-style "Hai Yue" calligraphy, Song dragon ink paintings, late-Ming and Qing calligraphy by Poshan and Zhangxue, paintings by Biyan and Zhuchan, and works by He Shaoji, Zheng Banqiao, Zhang Daqian, and Feng Zikai. To the left rests a portion of the cranial relic of Master Xuanzang, transferred from Nanjing in the 1940s—the monk was ordained in Chengdu and lived here for five years; to the right rests a Buddha Śarīra brought from Bodh Gaya by the monk Nenghai in the 1920s. The "Tian Yi Xuan Cai" qipao embroidered with 248 Buddha figures by Ming consort Tian, the Qing hair-embroidered Water-Moon Guanyin, four blood-written sutras, and the Diamond Sutra pagoda painting—all part of the "Eight Views of Konglin"—are also housed here.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_01.jpg', 0),
  ('wenshuyuan_sa_02', 'wenshuyuan', 'Tea Garden and Vegetarian Hall', '茶园与香斋堂', 'The Tea Garden sits inside the monastery''s east garden, opened in 1988 alongside the Thousand-Buddha Peace Pagoda, and operates as a "Chan-monastery teahouse" in old-Chengdu style. Bamboo roofs, blue-brick paving, square tables, covered-bowl tea, and long-spouted copper kettles recreate a classic "bada cha" open-air teahouse serving Bi Tan Piao Xue, Zhu Ye Qing, Mao Feng, Tie Guan Yin, and Pu''er teas at around RMB 10–30 per person, with free hot-water refills and outside snacks allowed. The Xiangzhai Hall vegetarian restaurant sits next to the Tea Garden and is separate from the monks'' Wuguan Hall. The menu emphasizes Sichuan-style vegetarian cuisine: vegetarian Mapo tofu, vegetarian twice-cooked pork, sweet rice cake, monastery pickles, and full vegetarian set meals at RMB 20–60 per person, plus luohan noodles and mushroom wonton. Together they create a "worship, tea, dine" loop, expressing the monastery''s "humanistic Buddhism" approach. Just outside the gate, Wenshu Yuan Street hosts Chengdu classics such as Long Chaoshou (Wenshu Yuan main branch), Yan Taipo Guokui, and Zhong Sui Jiao, making the visit a combined temple-and-old-streets experience.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_02.jpg', 1),
  ('wenshuyuan_sa_03', 'wenshuyuan', 'Mahavira Hall', '大雄宝殿', 'The Mahavira Hall is the third hall on the central axis, originally built by Chan Master Cidu and rebuilt by Abbot Zhangbai. Standing 10.56 m tall in single-eaved Xieshan style, it is the largest and highest-ranked hall in the monastery. The central glass shrine houses a bronze Sakyamuni Buddha cast in 1829, flanked by bronze Kasyapa and Ananda figures—the most important Qing-dynasty bronze trio in the monastery and part of the "Eight Views of Konglin." Two Burmese jade Buddhas brought back in 1923 and 1938 by monks Xinglin and Dengyun sit in the shrine ("Burmese Jade in the Shrine"). Two ancient fir trees, each 15 m tall, stand behind the hall: descendants of the firs that flanked the old gate and under which Master Cidu took shelter ("Twin Firs Auspicious"). Free incense is provided—one stick per person, taken with both hands.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_03.jpg', 2),
  ('wenshuyuan_sa_04', 'wenshuyuan', 'Thousand Buddhas Peace Pagoda and Stele Corridor', '千佛和平塔与碑廊', 'The Thousand-Buddha Peace Pagoda stands in the eastern courtyard between the Canon Library and Wenshu Pavilion. Built in 1988, it was inscribed and coupleted by Zhao Puchu, then president of the Buddhist Association of China. The six-sided, eleven-story iron pagoda rises 21 meters and bears 1,000 cast Buddha images. Six dragons crown the spire with bells that ring in the wind. The east, west, and north sides are lined with stele corridors displaying dozens of stone tablets—Qing imperial and official inscriptions, poems by the monastery''s abbots Cidu, Benyuan, Xuanlin, Nenghai, Biannen, and Weixian, and Buddhist maxims. The two-tiered surrounding walls are decorated with four-season floral motifs and bas-reliefs of the Journey to the West, symbolizing the two-way transmission of dharma along the Silk Road. Ginkgo, camphor, plum, and magnolia trees frame the pagoda, making it the monastery''s most contemplative garden.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_04.jpg', 3),
  ('wenshuyuan_sa_05', 'wenshuyuan', 'Hall of Three Great Beings (Guanyin Hall)', '三大士殿（观音殿）', 'The Hall of the Three Great Beings, also called the Hall of Guanyin, is the second hall on the central axis and the only one of the six that retains its original 1697 Kangxi-period structure. Three principal statues stand on a central platform: Manjushri on a blue lion (wisdom), Guanyin holding a willow branch and pure-water vase (compassion), and Samantabhadra on a white elephant (vow and action). Side bays house Wenchang Dijun and Saintly Lord Guan, reflecting the late-imperial Sichuanese fusion of Buddhist, Daoist, and Confucian popular devotion. Behind the hall stands the bronze Weituo guardian, cast by Abbot Benyuan in 1829. The lintel couplet by late-Qing Chengdu literatus Fang Hezhai—"What is done let be done, what is let go let be let go, what ends, ends; wisdom is born of awakening, awakening is born of ease, what arises, arises and yet does not arise"—expresses the Chan spirit of resolving the matter at hand.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_05.jpg', 4),
  ('wenshuyuan_sa_06', 'wenshuyuan', 'Mountain Gate (Hall of Heavenly Kings)', '山门（天王殿）', 'The Main Gate / Hall of Heavenly Kings is the first hall on the central axis, originally built by Chan Master Cidu and rebuilt by Abbot Benyuan, facing south with a five-bay facade in classic Kangxi–Daoguang Sichuanese style. The gate and hall are combined: the two Heng-Ha guardians stand at the door, Maitreya is enshrined at the center (with Weituo behind), and the Four Heavenly Kings—Dhṛtarāṣṭra, Virūḍhaka, Virūpākṣa, and Vaiśravaṇa—flank the hall, each holding a sword, pipa, parasol, or serpent/dragon to symbolize favorable weather. The pillars bear the couplet by Qing abbot Fu Wenjiwei. In front, the three-story Drum and Bell towers face each other: the bell tower houses a 4,500+ kg Qing-dynasty bronze bell, the drum tower its great drum. Their morning bell and evening drum mark the monastic schedule and ritual calendar.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_06.jpg', 5),
  ('wenshuyuan_sa_07', 'wenshuyuan', 'Dharma Hall (Medicine Buddha Hall)', '说法堂（药师殿）', 'The Dharma Hall, also called the Hall of Bhaisajyaguru, is the fourth hall on the central axis and is said to occupy the site of the original Tang-era Xinxiang Monastery. A double-eaved Xieshan Qing-dynasty building, it contains a brick ordination platform used for precepts ceremonies, lay refuge, and sutra lectures. At center, beneath a jeweled canopy, sits Bhaisajyaguru, the Medicine Buddha of the eastern Lapis Lazuli world, flanked by the twelve yakṣa generals—each guarding one of the twelve traditional double-hours and zodiac animals. The back wall bears the Kangxi Emperor''s 1702 inscription "Konglin" (Empty Forest)—the calligraphic origin of the monastery''s alternate name "Konglin Tang" and the first of the "Eight Views of Konglin." The Sichuanese-style Buddhist chanting preserved here was inscribed on Chengdu''s seventh intangible cultural heritage list in 2021.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_07.jpg', 6),
  ('wenshuyuan_sa_08', 'wenshuyuan', 'Manjushri Pavilion', '文殊阁', 'Wenshu Pavilion stands at the northernmost end of the central axis. Built in 1997 under the 17th abbot Xuanlin, it occupies about 1,000 square meters in a three-story Qing-style double-eave structure. The first floor, the "Konglin Lecture Hall," seats several hundred for dharma talks, meditation, and Chan practice. The second floor houses the "Konglin Buddhist Library," with sutras, modern Buddhist scholarship, and journals for both laypeople and researchers. The third floor, the "Ten-Thousand-Buddha Hall," enshrines the central principal Buddha surrounded by a thousand Buddhas on the four walls, creating the monastery''s most contemplative space. The pavilion closes the central axis and complements the five earlier historic halls, forming a "front-court, rear-market" plan that joins devotional and cultural functions.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_08.jpg', 7),
  ('wenshuyuan_sa_09', 'wenshuyuan', 'Garden and Life-Release Pond', '园林与放生池', 'The Wenshu Monastery gardens center on the east and west gardens flanking the central axis and the Release Pond—landscaped together with the Thousand-Buddha Pagoda in 1988. The Release Pond sits between the Hall of Heavenly Kings and the Mahavira Hall in an irregular L shape, home to koi, goldfish, and turtles, with water lilies, calamus, and willows along the banks; a Qing-era "Release Pond" stele stands on the north bank in Manchu and Chinese. The Tingsong Waterside Pavilion on the west bank responds visually to the Bell and Drum towers. The east garden ("Hearing and Reflecting") and west garden ("Cultivating and Realizing") flank the central axis, with Taihu rocks, ginkgo, camphor, plum, magnolia, crepe myrtle, and paths of bamboo. Covered corridors tie the halls, gardens, and the Peace Pagoda into a single meandering composition. The two ancient firs at the rear of the Mahavira Hall, said to mark Master Cidu''s hermitage, are the "Twin Firs Auspicious" of the "Eight Views of Konglin."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_09.jpg', 8),
  ('wenshuyuan_sa_10', 'wenshuyuan', 'Main Gate (Screen Wall)', '正门（照壁）', 'The front gate and spirit wall stand at the south end of the Wenshu Monastery central axis, the first visual anchor before visitors reach the main gate. About 8 metres high and shaped like the Chinese character for "pin" in brick and stone, the wall bears the monastery name and a couplet meaning "wisdom deep as heaven and earth, lineage surpassing past and present," said to be in the hand of Chan Master Cidu of the Kangxi reign. The wall faces the city street on one side and the temple gate on the other—a classic Chinese monastic gesture of modesty and containment. Two side gates flank the central entrance, and the temple itself is open and free, with public transit and the city road reaching right up to the wall.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/wenshuyuan_sa_10.jpg', 9),
  ('chengdu_wuhou_shrine_sa_01', 'chengdu_wuhou_shrine', 'South Gate & Screen Wall (Chengdu Wuhou Shrine)', '南门与照壁（成都武侯祠）', 'The vermilion screen wall outside the south gate bears the black-and-gold "Han Zhao Lie Miao" plaque—signaling that this is no ordinary Zhuge shrine, but a nationally unique co-enshrinement of sovereign and minister. The wall is ~18m long and ~6m tall, built of grey brick. The south plaza, shaded by green trees, often features Sichuan-opera face-changing performers and bronze statues. The "red wall with bamboo shadow" is one of Chengdu''s most photogenic classical backdrops. During Spring Festival, the plaza hosts lantern shows and intangible-heritage markets.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_01.jpg', 0),
  ('chengdu_wuhou_shrine_sa_02', 'chengdu_wuhou_shrine', 'Main Gate — Han Zhao Lie Miao (Chengdu Wuhou Shrine)', '大门——汉昭烈庙（成都武侯祠）', 'The main gate bears the gold character "Han Zhao Lie Miao," calligraphied by Guo Moruo in 1955. The gate is a single-eave overhanging-gable building, vermilion doors with bronze beast-head knockers, flanked by two stone lions carved in the Kangxi era. The plaque is the key to understanding the shrine''s unique layout: as minister, Zhuge Liang''s shrine should be in front, but during the early Ming the order was reversed—Emperor Liu Bei''s "Han Zhao Lie Miao" stands ahead, Zhuge''s behind. The tour officially begins here.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_02.jpg', 1),
  ('chengdu_wuhou_shrine_sa_03', 'chengdu_wuhou_shrine', 'Second Gate & Tang Stele — Three Absolutes Stele (Chengdu Wuhou Shrine)', '二门与唐碑——三绝碑（成都武侯祠）', 'Crossing the main gate, the second gate bears Guo Moruo''s 1944 "Wuhou Shrine" plaque, echoing the main gate''s "Han Zhao Lie Miao" in the unique sovereign-minister protocol. Inside stands the "Three Absolutes Stele"—3.4m tall, 1.3m wide—composed by Prime Minister Pei Du, calligraphed by Liu Gongchuo, and carved by Lu Jian, 809 AD. The pavilion houses 20+ steles from Han to Qing dynasties, making it a one-stop showcase of 1,200 years of stone inscription. Visitors gain the key view of the central axis: Liu Bei''s hall in front, Zhuge''s hall behind.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_03.jpg', 2),
  ('chengdu_wuhou_shrine_sa_04', 'chengdu_wuhou_shrine', 'Liu Bei''s Hall — Main Hall of Han Zhao Lie Miao (Chengdu Wuhou Shrine)', '刘备殿——汉昭烈庙正殿（成都武侯祠）', 'Liu Bei''s Hall is the 3rd bay of the central axis, ~12m high, hung with the plaque "Ye Shao Gao Guang." Centered is the gilded seated statue of Emperor Zhaolie Liu Bei—robed, holding the jade tablet, dignified—the shrine''s principal deity. Flanking the emperor are Guan Yu''s three generations (Guan Ping, Guan Xing, Zhang Zun) and Zhang Fei''s three generations (Zhang Bao, Zhang Zun); the side walls display 14 Shu Han elite statues (Zhuge Liang, Pang Tong, Zhao Yun, Ma Chao, Huang Zhong). The stone balustrade is finely carved, and the hall houses historic plaques including Zhuge Liang''s "Collection" plaque and Lu You''s poetry stele. Liu Bei''s birthday celebration is held on the 26th day of the 6th lunar month.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_04.jpg', 3),
  ('chengdu_wuhou_shrine_sa_05', 'chengdu_wuhou_shrine', 'Connecting Hall — Chu Shi Biao Stone Carving (Chengdu Wuhou Shrine)', '过厅——出师表石刻（成都武侯祠）', 'The connecting hall is the 4th bay on the central axis, functioning as a transition between Liu Bei''s and Zhuge Liang''s halls. Its south and north walls bear the "Chu Shi Biao" carvings—Yue Fei''s calligraphy of the "Former" and "Latter Memorials." Yue Fei''s running script is vigorous and powerful, bridging the two loyal figures 700 years apart. The carved plaques were re-engraved in the Guangxu era. The hall bears the "Jingyuan Tang" (Tranquility Hall) plaque, quoting Zhuge Liang''s famous injunction: "Without tranquility, one cannot achieve far-reaching goals."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_05.jpg', 4),
  ('chengdu_wuhou_shrine_sa_06', 'chengdu_wuhou_shrine', 'Zhuge Liang''s Hall — Jingyuan Tang (Chengdu Wuhou Shrine)', '诸葛亮殿——静远堂（成都武侯祠）', 'Zhuge Liang''s Hall, the 13m-high endpoint of the central axis, bears the Qing prince''s "Eternal Fame" plaque. Inside, three generations of the Zhuge family are enshrined as gilded statues. Above Zhuge Liang''s image is the "Yi-Zhou Sage" plaque—equating him to the legendary minister Yi Yin. The veranda displays the famous "Gongxin Couplet" by Zhao Fan (late Qing), essential for understanding Sichuan governance philosophy. The hall also houses the "Three Absolutes" original text, a Ming bronze drum, and Qing-era epigraphy exhibits.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_06.jpg', 5),
  ('chengdu_wuhou_shrine_sa_07', 'chengdu_wuhou_shrine', 'Sanyi Temple (Chengdu Wuhou Shrine)', '三义庙（成都武侯祠）', 'Sanyi Temple, originally built in 1672 and relocated in 1998, now forms an independent courtyard at the southern end of the heritage zone. It enshrines the three sworn brothers: Liu Bei in the center, Guan Yu left, Zhang Fei right. The east/west wings display woodblock prints of Romance of the Three Kingdoms, replica weapons, and Guan Yu cultural exhibits. The temple complements the central axis''s "sovereign-minister" theme with a "brotherly loyalty" focus. Guan Yu''s birthday (24th day of 6th lunar month) features ceremonies and Sichuan-opera performances.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_07.jpg', 6),
  ('chengdu_wuhou_shrine_sa_08', 'chengdu_wuhou_shrine', 'Guihe Tower, Qin Pavilion & Garden Area (Chengdu Wuhou Shrine)', '桂荷楼、琴亭与园林区（成都武侯祠）', 'The garden area west of the main axis centers on the Guihe Pond, with the Qing-era civilian-style Guihe Tower, the hexagonal Qin Pavilion (named for Zhuge Liang''s "Empty City Strategy"), and several smaller structures—Tingli Pavilion, Bicao Xuan, a boat pavilion, and a bonsai garden. The garden employs the "borrowed scenery" technique, pulling distant views of Zhuge Liang''s Hall, Hui Ling Tomb, and the city wall into the pond''s reflections. Autumn brings osmanthus and lotus together, while winter features red plum blossoms and stone lanterns. The garden is also home to calligraphy steles of "Chu Shi Biao" and "Jie Zi Shu."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_08.jpg', 7),
  ('chengdu_wuhou_shrine_sa_09', 'chengdu_wuhou_shrine', 'Hui Ling — Joint Burial Tomb of Emperor Zhaolie Liu Bei and Empresses Gan & Wu', '惠陵——蜀汉昭烈帝刘备与甘、吴二皇后合葬陵', 'Hui Ling is located at the northwest of the heritage zone, distributed in a "reverse pinwheel" layout with Han Zhao Lie Miao and Wuhou Shrine. The burial mound is ~12m high, 180m in circumference, ~3,000 sqm. Liu Bei was entombed here after his death at Baidi City in 223 AD—the tomb has never been looted in 1,780 years, protected by both the people''s loyalty and the Ming-Qing tomb guardians. The 1953 excavation of the tomb passage revealed gold, jade, swords, and horse-and-chariot artifacts. The mound, tomb passage, que-fang, and corner towers form a complete imperial-tomb architectural group.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_09.jpg', 8),
  ('chengdu_wuhou_shrine_sa_10', 'chengdu_wuhou_shrine', 'Jinli Folk Street & Waterside Pavilion (Chengdu Wuhou Shrine · Folk Area)', '锦里与水榭（成都武侯祠·民俗区）', 'Jinli Folk Area, opened in 2004, is Chengdu''s first "Three Kingdoms + western Sichuan folk" themed block, ~550m long, in western Sichuan folk-house style: grey-tile white-wall houses, bluestone paths, wooden archways, and overhanging eaves along the Jinli watercourse. Three highlights: ①Snacks—over 100 Sichuan-style eateries (San Da Pao, Bo Bo Ji, etc.); ②Intangible heritage—12 western Sichuan crafts (Shu embroidery, lacquerware, silver filigree, etc.); ③Performances—three daily Sichuan-opera shows. The waterside pavilion, a riverside teahouse, offers a perfect view of Jinli and the shrine''s red wall at night. Year-round red lanterns and Three Kingdoms flags decorate the street, with over 100,000 daily visitors during Spring Festival.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_wuhou_shrine_sa_10.jpg', 9)
